def build_prompt(task, context, examples=None, fmt=None):
    parts = [f"Task: {task}"]
    if examples:
        parts.append("Examples:")
        for inp, out in examples:
            parts.append(f"Input: {inp}\nOutput: {out}")
    parts.append(f"Context:\n{context}")
    if fmt:
        parts.append(f"Respond in this format:\n{fmt}")
    return "\n\n".join(parts)

TESTS = [("Loved every minute", "POS"),
         ("Total waste of money", "NEG"),
         ("Best purchase this year", "POS")]

def score(system):
    hits = 0
    for text, gold in TESTS:
        pred = ask(system, f"Review: {text}").upper()
        hits += gold in pred
    return hits / len(TESTS)

print(score("Label sentiment POS or NEG. One word only."))
